-- s1_room_212_wake: Room 212
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's1_room_212_wake',
  'Room 212',
  'You wake up and it takes a second to remember where you are.

The ceiling is unfamiliar. The light coming through the curtains is wrong — facing the parking lot, not your backyard. Someone on the floor is already playing music. The Clash, maybe. Or a bad copy of it on a cassette that''s been recorded too many times.

Danny is already gone. His bed is made in the rough way of someone who learned to make beds and doesn''t care about it. His desk has a row of textbooks, a cassette player, and a photograph you can''t quite see from across the room.

On the whiteboard by the door: a phone message in someone else''s handwriting. *Danny — Mom called. Call back when you can.*

You have three things to do today. You can only do two of them well.',
  '[{"id":"s1_wake_get_food","label":"Get to the dining hall before it gets crowded","time_cost":1,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You fold your schedule into your back pocket and go. The hallway smells like industrial cleaner and someone''s Aqua Net. You find the dining hall by following the noise.","outcome":{"text":"The eggs are institutional. The orange juice is fine. You sit alone at the end of a long table and watch the room fill up. Miguel from 214 drops his tray across from you without asking. ''You''re 212, right?'' he says. You are.","deltas":{"energy":1,"stress":-1,"resources":{"socialLeverage":1}}},"relational_effects":{"npc_floor_miguel":{"trust":1,"reliability":0,"emotionalLoad":0}},"set_npc_memory":{"npc_floor_miguel":{"met":true,"knows_name":true}}},{"id":"s1_wake_explore","label":"Walk the campus before everyone else is out","time_cost":1,"energy_cost":1,"identity_tags":["risk"],"reaction_text":"You take the campus map from orientation and fold it badly. The brick paths all look the same. You find Whitmore Hall, the bookstore, and a shortcut behind the science building that might be useful.","outcome":{"text":"You''re back before 8. Danny still isn''t. You know where your classrooms are now, which is more than most people can say. The anxiety is the same but it has fewer practical targets.","deltas":{"energy":-1,"stress":-1,"resources":{"knowledge":2}}}},{"id":"s1_wake_wait","label":"Wait for Danny to come back — you don''t want to navigate this alone","time_cost":1,"energy_cost":0,"identity_tags":["safety","people"],"reaction_text":"You sit on your bed. You read the message on the whiteboard again. You look at the photograph on Danny''s desk — a woman, maybe his mother, squinting into the sun.","outcome":{"text":"Danny comes back at 8:15 with a dining hall cup of coffee he clearly didn''t enjoy. He sees you on the bed. ''You haven''t eaten yet?'' There''s no judgment in it. ''Come on,'' he says. ''I''ll show you where they keep the good cereal.''","deltas":{"energy":0,"stress":0,"resources":{"socialLeverage":2}}},"relational_effects":{"npc_roommate_danny":{"trust":2,"reliability":1,"emotionalLoad":0}}}]'::jsonb,
  ARRAY['arc_one_core', 'roommate', 'onboarding'],
  '{"min_day_index":1,"max_day_index":1,"max_total_runs":1}'::jsonb,
  200,
  true
)
