-- s1_danny_first_conversation: The Better Desk
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's1_danny_first_conversation',
  'The Better Desk',
  'It''s evening. You''re both in the room for the first time at the same time with nowhere to be.

Danny is at his desk — the one by the window, the one that was already claimed when you arrived — flipping through what looks like a physics textbook. His cassette player is going. The Pretenders. Quiet enough to be background, loud enough to notice.

He got the better desk. You haven''t mentioned it. You''re not sure if you''re going to.

He turns around. ''Where are you from?'' he asks. Not unfriendly. Just starting somewhere.',
  '[{"id":"s1_danny_conv_surface","label":"Keep it surface — town, major, standard orientation answers","time_cost":0,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You give him the version you''ve already rehearsed. He nods. He gives you his version back. You learn: Parma, Ohio. Mechanical engineering. Dad works at the Ford plant.","outcome":{"text":"It''s polite and accurate and tells you almost nothing useful about each other. He turns back to his textbook. You have a roommate you know how to avoid disappointing. That''s something.","deltas":{"stress":0}},"relational_effects":{"npc_roommate_danny":{"trust":0,"reliability":1,"emotionalLoad":0}},"set_npc_memory":{"npc_roommate_danny":{"met":true,"knows_name":true,"first_conv_depth":"surface"}}},{"id":"s1_danny_conv_real","label":"Say something true — tell him you''re not sure you picked the right major","time_cost":0,"energy_cost":1,"identity_tags":["risk","people"],"reaction_text":"It comes out before you''ve decided to say it. He looks up from the textbook. A beat.","outcome":{"text":"''Yeah,'' Danny says. ''Me too.'' He closes the physics book. ''I picked engineering because my dad picked it. I haven''t told anyone that.'' The Pretenders keep playing. You talk for an hour. You never address the desk.","deltas":{"stress":-2,"energy":-1,"resources":{"socialLeverage":3}}},"relational_effects":{"npc_roommate_danny":{"trust":3,"reliability":0,"emotionalLoad":1}},"set_npc_memory":{"npc_roommate_danny":{"met":true,"knows_name":true,"first_conv_depth":"real","knows_your_doubt":true}}},{"id":"s1_danny_conv_desk","label":"Mention the desk — calmly, not as a fight","time_cost":0,"energy_cost":1,"identity_tags":["risk"],"reaction_text":"You say it like you''re asking about the weather. ''Hey — how''d you end up with the window desk?'' Danny blinks. He wasn''t expecting it.","outcome":{"text":"''I just... put my stuff there.'' A pause. ''You want it?'' You say no, not really, you just wanted to ask. He nods slowly. Something shifts — not badly. He knows you''re someone who says things. That changes the room.","deltas":{"energy":-1,"stress":-1,"resources":{"socialLeverage":1}}},"relational_effects":{"npc_roommate_danny":{"trust":1,"reliability":2,"emotionalLoad":1}},"set_npc_memory":{"npc_roommate_danny":{"met":true,"knows_name":true,"knows_you_speak_up":true}}}]'::jsonb,
  ARRAY['arc_one_core', 'roommate', 'social'],
  '{"min_day_index":1,"max_day_index":2,"max_total_runs":1}'::jsonb,
  150,
  true
)
