-- s1_danny_music_friction: The Volume
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's1_danny_music_friction',
  'The Volume',
  '11pm. You have a reading due for Heller''s sociology class tomorrow morning.

Danny is listening to London Calling at a volume that is not quite loud enough to complain about but loud enough that you''ve read the same paragraph four times.

He doesn''t know you''re trying to work. Or he does and assumes you''d say something. Or he doesn''t care. You can''t tell which.

There''s no way to text him from across the room. You have to either say something or not say something.',
  '[{"id":"s1_friction_say_something","label":"Ask him to turn it down — direct, no drama","time_cost":0,"energy_cost":1,"identity_tags":["risk"],"skill_modifier":"grit","reaction_text":"''Hey — any chance you can turn it down? I''ve got reading.'' He looks up. A second of calibration.","outcome":{"text":"He turns it down without making it weird. ''Sorry, didn''t realize.'' You get the reading done. Nothing is damaged. In fact something is slightly better — you''ve established that the room has negotiable terms.","deltas":{"energy":-1,"stress":-1,"resources":{"knowledge":1}}},"relational_effects":{"npc_roommate_danny":{"trust":1,"reliability":1,"emotionalLoad":0}}},{"id":"s1_friction_let_it_go","label":"Put up with it — not worth the friction","time_cost":0,"energy_cost":1,"identity_tags":["safety"],"reaction_text":"You reread the paragraph. You reread it again. You give up on the nuance and get the general shape of it.","outcome":{"text":"You get through the reading. Sort of. The argument Heller is making about social structures has edges you''ll have to find later. Danny turns it off at midnight and says goodnight like nothing happened. Because nothing did.","deltas":{"energy":-1,"stress":1,"resources":{"knowledge":0}}},"relational_effects":{"npc_roommate_danny":{"trust":0,"reliability":0,"emotionalLoad":-1}}},{"id":"s1_friction_leave","label":"Take your books to the library","time_cost":1,"energy_cost":1,"identity_tags":["achieve"],"reaction_text":"You gather your stuff without explanation. Danny watches but doesn''t ask.","outcome":{"text":"The library is cold and quiet and closes at 10. You get more done in 45 minutes than you would have in two hours in the room. You get back at 10:15. Danny is asleep. The cassette player is off. Tomorrow you''ll have to decide if this is your solution now.","deltas":{"stress":0,"energy":-1,"resources":{"knowledge":2}}}}]'::jsonb,
  ARRAY['arc_one_core', 'roommate', 'social'],
  '{"min_day_index":2,"max_day_index":4,"max_total_runs":1,"requires_npc_met":["npc_roommate_danny"]}'::jsonb,
  120,
  true
)
