-- s1_danny_revealing_moment: The Letter
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's1_danny_revealing_moment',
  'The Letter',
  'You come back from your afternoon class to find Danny sitting on his bed with a letter open in his lap.

He doesn''t hear you come in. He''s just sitting there, reading something he''s clearly already read twice. His posture is different — smaller, somehow, in a way that has nothing to do with the room.

You recognize this. Not the letter. The shape of what a letter from home can do to a person.

He looks up. ''Hey.'' He folds it quickly. ''How was class?''',
  '[{"id":"s1_danny_letter_ask","label":"Ask if he''s okay — directly","time_cost":0,"energy_cost":1,"identity_tags":["people"],"reaction_text":"He looks at you for a second. Then: ''My dad''s having some trouble at the plant. Nothing serious. Probably.'' He says probably like he knows it means something.","outcome":{"text":"You don''t try to fix it. You just sit with it for a minute. He seems to appreciate that more than he''d appreciate advice. Something changes in the room — not fixed, just real.","deltas":{"energy":-1,"resources":{"socialLeverage":2}}},"relational_effects":{"npc_roommate_danny":{"trust":3,"reliability":0,"emotionalLoad":2}},"set_npc_memory":{"npc_roommate_danny":{"shared_vulnerability":true}}},{"id":"s1_danny_letter_ignore","label":"Let him have it — change the subject to something neutral","time_cost":0,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You ask about the homework. He follows your lead. The letter goes in his desk drawer.","outcome":{"text":"You gave him an out and he took it. That''s a kind of consideration. But you also stayed on the surface when the room offered you something deeper. He''ll remember both things.","deltas":{"stress":-1}},"relational_effects":{"npc_roommate_danny":{"trust":0,"reliability":1,"emotionalLoad":-1}}},{"id":"s1_danny_letter_share","label":"Tell him you got something from home too — make it mutual","time_cost":0,"energy_cost":1,"identity_tags":["people","risk"],"reaction_text":"You pull out the postcard your mother sent — written before you left, arrived yesterday. You hand it to him. He reads it. Hands it back.","outcome":{"text":"''She sounds like she misses you,'' Danny says. ''Yeah,'' you say. ''So does yours, I think.'' He laughs — the first real one. You''ve found a way to be in the same situation instead of separate ones.","deltas":{"stress":-2,"energy":-1,"resources":{"socialLeverage":3}}},"relational_effects":{"npc_roommate_danny":{"trust":4,"reliability":1,"emotionalLoad":1}},"set_npc_memory":{"npc_roommate_danny":{"shared_vulnerability":true,"knows_about_your_family":true}}}]'::jsonb,
  ARRAY['arc_one_core', 'roommate', 'home', 'social'],
  '{"min_day_index":4,"max_day_index":5,"max_total_runs":1,"requires_npc_met":["npc_roommate_danny"]}'::jsonb,
  100,
  true
)
