-- s2_syllabus_moment: Whitmore 101
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's2_syllabus_moment',
  'Whitmore 101',
  'Intro to Sociology. Whitmore 101. 9am.

You find a seat in the middle — not front row, not back. Professor Heller comes in without fanfare, sets a battered leather bag on the desk, and starts distributing a stapled packet before anyone is settled.

The syllabus is four pages. The reading list alone is a page and a half. There''s a midterm worth 40% and a final paper requiring ''original fieldwork on a social institution of your choosing.'' The first reading is due Friday.

The person next to you flips to the back of the packet and says, quietly, ''Oh god.'' You don''t know if that''s better or worse than everyone else who said nothing.',
  '[{"id":"s2_syllabus_ask_neighbor","label":"Ask the person next to you if this load seems normal","time_cost":0,"energy_cost":0,"identity_tags":["people","risk"],"reaction_text":"She looks up — dark hair, reading glasses pushed up on her head, a copy of the syllabus already annotated with a green pen. ''Normal for Heller, I''ve heard. I''m Diane.''","outcome":{"text":"Diane is a sophomore who took Heller''s class late because of a scheduling conflict. She knows how he runs things. She offers to share notes from a friend who took it last year. You have an asset before the class has technically started.","deltas":{"stress":-1,"resources":{"knowledge":2,"socialLeverage":1}}}},{"id":"s2_syllabus_alone","label":"Process it alone — make your own read of what''s actually hard","time_cost":0,"energy_cost":1,"identity_tags":["achieve","safety"],"skill_modifier":"focus","reaction_text":"You go through it carefully. The reading is dense but not impossible. The paper is the real challenge — fieldwork means planning ahead, not cramming.","outcome":{"text":"By the time Heller starts talking, you have three asterisks and a question you actually want to ask. You don''t ask it. But you have it.","deltas":{"energy":-1,"resources":{"knowledge":3}}}},{"id":"s2_syllabus_approach_heller","label":"Approach Heller after class — introduce yourself","time_cost":1,"energy_cost":2,"identity_tags":["risk","achieve"],"reaction_text":"Most students file out. You wait. Heller is repacking his bag when you walk up. He looks at you over his glasses without impatience.","outcome":{"text":"You say you have a question about the fieldwork component. He lights up — actually lights up. You spend ten minutes talking about what counts as a social institution. He says your idea isn''t bad. He knows your name now. That changes things.","deltas":{"energy":-2,"stress":-1,"resources":{"knowledge":4,"socialLeverage":2}}},"relational_effects":{"npc_prof_heller":{"trust":2,"reliability":2,"emotionalLoad":0}},"set_npc_memory":{"npc_prof_heller":{"knows_your_name":true,"first_impression":"curious"}}}]'::jsonb,
  ARRAY['arc_one_core', 'academic', 'study'],
  '{"min_day_index":2,"max_day_index":2,"max_total_runs":1}'::jsonb,
  180,
  true
)
