-- s2_first_gap: The Part You Didn't Follow
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's2_first_gap',
  'The Part You Didn''t Follow',
  'Wednesday lecture. Heller is talking about Durkheim — anomie, social cohesion, the way systems hold people in place without them noticing.

You followed it for the first twenty minutes. Then he made a pivot and you lost the thread. You have ''anomie = normlessness?'' in your notebook followed by two inches of blank space.

The student three seats over has a full page of notes.

Office hours are Thursday 2-4pm. Whitmore 318. You have that time slot. You were going to use it for something else.',
  '[{"id":"s2_gap_office_hours","label":"Go to office hours — find the sheet outside Whitmore 318 and show up","time_cost":1,"energy_cost":1,"identity_tags":["achieve","risk"],"skill_modifier":"grit","reaction_text":"The sheet is there, taped at eye level. Two names already signed. You add yours. Thursday, 2:15.","outcome":{"text":"Heller doesn''t make you feel stupid for not following. He reframes Durkheim in a different order and it clicks. You''re there for 25 minutes. You walk out understanding something instead of knowing something, which feels completely different.","deltas":{"energy":-1,"stress":-2,"resources":{"knowledge":4}}},"relational_effects":{"npc_prof_heller":{"trust":1,"reliability":2,"emotionalLoad":0}}},{"id":"s2_gap_study_group","label":"Find the study group forming in the library — Miguel mentioned it","time_cost":1,"energy_cost":1,"identity_tags":["people","achieve"],"reaction_text":"Miguel said third floor, near the reference stacks, 7pm. You find four people around a table, including Diane from the first class.","outcome":{"text":"It''s less efficient than office hours and more useful than studying alone. Someone else had the same gap you did. You fill it together. You also learn that Diane has already started her fieldwork paper outline.","deltas":{"energy":-1,"resources":{"knowledge":2,"socialLeverage":2}}}},{"id":"s2_gap_push_through","label":"Push through alone — reread the chapter until it lands","time_cost":1,"energy_cost":2,"identity_tags":["achieve","safety"],"skill_modifier":"focus","reaction_text":"You go back to the dorm with the textbook. Danny is out. You sit at your desk and read Durkheim three times.","outcome":{"text":"By the third read, you have something. Not everything, but enough. What it cost: two hours, your afternoon slot, and the creeping feeling that this is how it''s going to be.","deltas":{"energy":-2,"stress":1,"resources":{"knowledge":3}}}},{"id":"s2_gap_minimize","label":"Let it go — it''s only the first week","time_cost":0,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You close the notebook.","outcome":{"text":"The gap stays. You won''t know what it costs until the midterm shows you. For now you have your afternoon back.","deltas":{"stress":-1,"resources":{"knowledge":-1}}}}]'::jsonb,
  ARRAY['arc_one_core', 'academic', 'study'],
  '{"min_day_index":3,"max_day_index":4,"max_total_runs":1}'::jsonb,
  130,
  true
)
