-- s3_bookstore_line: The Bookstore
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's3_bookstore_line',
  'The Bookstore',
  'The line at the Harwick Bookstore starts outside the door and wraps toward the student union.

You have your class list. You''ve done the math in your head twice and don''t like the answer. The sociology text is $34. The chemistry lab manual is $18. The intro economics anthology — required, no substitutions — is $47.

A hand-lettered sign on the door: *No checks over $75 without ID. No returns after 48 hours.*

The person ahead of you is writing in a notebook, comparing prices — figuring out which books they absolutely need versus which ones they might share or find at the library.',
  '[{"id":"s3_books_buy_all","label":"Buy everything on the list","time_cost":1,"energy_cost":0,"identity_tags":["achieve","safety"],"requires_resource":{"key":"cashOnHand","min":120},"reaction_text":"You write the check. The cashier doesn''t look up.","outcome":{"text":"You have everything you need. The money is gone in a way that''s hard to look at directly. Your stack of books on the desk looks like intention.","deltas":{"stress":1,"resources":{"cashOnHand":-130,"knowledge":2}}}},{"id":"s3_books_selective","label":"Buy only the first two weeks'' worth — figure out the rest later","time_cost":1,"energy_cost":1,"identity_tags":["risk"],"reaction_text":"You buy the sociology text and the lab manual. The economics anthology you''ll try to find at the library.","outcome":{"text":"The library has two copies on reserve — two-hour checkout limit. You write down the reserve desk hours on the back of your hand.","deltas":{"energy":-1,"stress":0,"resources":{"cashOnHand":-52,"knowledge":1}}}},{"id":"s3_books_ask_around","label":"Ask the person ahead of you if they want to split books","time_cost":1,"energy_cost":1,"identity_tags":["people","risk"],"reaction_text":"They look up from their notebook. ''Which classes are you in?''","outcome":{"text":"His name is James. He''s in two of the same courses. You split the economics anthology — he buys it, you Xerox the relevant chapters at 10 cents a page. You save $23 and have someone to sit next to in Econ.","deltas":{"energy":-1,"stress":-1,"resources":{"cashOnHand":-15,"socialLeverage":2,"knowledge":1}}}}]'::jsonb,
  ARRAY['arc_one_core', 'money', 'study'],
  '{"min_day_index":1,"max_day_index":2,"max_total_runs":1}'::jsonb,
  170,
  true
)
