-- s3_pizza_social: The Pizza Question
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's3_pizza_social',
  'The Pizza Question',
  'Miguel knocks on your door at 7pm.

''Group of us are going to Sal''s — it''s like a ten minute walk. You in?''

You check your wallet without obviously checking your wallet. You have seventeen dollars and change. Textbooks are paid for or not. The dining hall is covered.

But you''ve been doing quiet math all week and seventeen feels like it needs to last longer than the weekend.',
  '[{"id":"s3_pizza_go","label":"Go — $3 is worth it for the room","time_cost":1,"energy_cost":1,"identity_tags":["people","risk"],"reaction_text":"Miguel''s ''group of us'' turns out to be five people, including Danny.","outcome":{"text":"The pizza is fine. The conversation is better. You learn that Carla from the third floor knows someone you went to camp with at age eleven — the kind of coincidence that feels significant at 18. The $3.50 is gone and the evening feels like something.","deltas":{"energy":-1,"stress":-2,"resources":{"cashOnHand":-4,"socialLeverage":3}}},"relational_effects":{"npc_floor_miguel":{"trust":1,"reliability":1,"emotionalLoad":0}}},{"id":"s3_pizza_excuse","label":"Make an excuse — say you have reading","time_cost":0,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"Miguel says ''no worries, next time'' genuinely. You close the door.","outcome":{"text":"You hear them come back at 10, laughing about something you don''t have the reference for. You tell yourself it doesn''t matter.","deltas":{"stress":1,"resources":{"knowledge":2}}}},{"id":"s3_pizza_honest","label":"Tell Miguel you''re watching spending — ask if there''s a cheaper option","time_cost":1,"energy_cost":1,"identity_tags":["risk","people"],"reaction_text":"You say it plainly. Miguel doesn''t blink. ''The dining hall''s got a dessert thing — just come there first, we''ll swing by after.''","outcome":{"text":"You go. You eat in the dining hall, then walk to Sal''s and split a Coke with Danny. Nobody tracks what anyone orders. The honesty cost nothing. That surprises you.","deltas":{"stress":-2,"energy":-1,"resources":{"cashOnHand":-1,"socialLeverage":2}}},"relational_effects":{"npc_floor_miguel":{"trust":2,"reliability":1,"emotionalLoad":0}}}]'::jsonb,
  ARRAY['arc_one_core', 'money', 'social', 'belonging'],
  '{"min_day_index":2,"max_day_index":4,"max_total_runs":1,"requires_npc_met":["npc_floor_miguel"]}'::jsonb,
  120,
  true
)
