-- s3_money_friction_event: The Lab Fee
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's3_money_friction_event',
  'The Lab Fee',
  'There''s a yellow slip in your campus mailbox.

Chemistry department. A lab fee — $22, due by Friday. It wasn''t listed in the tuition breakdown. It wasn''t mentioned at orientation. It just appeared.

$22 is not catastrophic. It is also not nothing.',
  '[{"id":"s3_fee_pay_now","label":"Pay it immediately — don''t let it become a thing","time_cost":1,"energy_cost":0,"requires_resource":{"key":"cashOnHand","min":22},"identity_tags":["safety","achieve"],"reaction_text":"You write a check. It clears. The yellow slip goes in the trash.","outcome":{"text":"Done. The anxiety cost more than the money. You now have a cleaner number in your head.","deltas":{"stress":-1,"resources":{"cashOnHand":-22}}}},{"id":"s3_fee_call_home","label":"Call home — ask if there are more surprise fees coming","time_cost":1,"energy_cost":1,"identity_tags":["people","safety"],"reaction_text":"The floor phone. Your father answers. You explain. He''s quiet for a moment — the specific quiet of someone doing math.","outcome":{"text":"''I''ll put something in the mail.'' The money is coming. The conversation was shorter than you wanted. You hang up knowing something about what this costs them.","deltas":{"stress":1,"energy":-1,"resources":{"cashOnHand":30}}}},{"id":"s3_fee_delay","label":"Set it aside — Friday is still a few days away","time_cost":0,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You put the slip back in your mailbox.","outcome":{"text":"The slip lives in the back of your mind at a low hum. On Thursday you pay it. The hum stops. You spent three days carrying it when you could have spent twenty minutes.","deltas":{"stress":2,"resources":{"cashOnHand":-22}}}}]'::jsonb,
  ARRAY['arc_one_core', 'money', 'study'],
  '{"min_day_index":3,"max_day_index":5,"max_total_runs":1}'::jsonb,
  110,
  true
)
