-- s4_orientation_fair: The Quad
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's4_orientation_fair',
  'The Quad',
  'The orientation fair is on the quad and it is exactly as much as it is.

Twenty-three folding tables with hand-lettered signs. Pre-med study group. The Harwick Herald. Model UN. The nuclear freeze coalition — a card table with a petition and two earnest sophomores in army surplus jackets. Young Republicans. Young Democrats, three feet to the left.

Miguel is already halfway through the fair, talking to someone at the newspaper table like they''ve met before. He waves you over but doesn''t push.

You have one afternoon slot. The fair closes at 4.',
  '[{"id":"s4_fair_newspaper","label":"Stop at The Harwick Herald — you''ve always been a decent writer","time_cost":1,"energy_cost":1,"identity_tags":["risk","achieve"],"reaction_text":"Karen — a junior, Herald press badge clipped to her flannel shirt — hands you a flyer. *First pitch meeting: Wednesday 7pm, Student Union 204.*","outcome":{"text":"Karen makes eye contact for exactly one second. ''You''d need a story idea by Wednesday.'' You have four days and no idea what you''d pitch. That''s either a problem or a starting point.","deltas":{"energy":-1,"resources":{"socialLeverage":1}}},"relational_effects":{"npc_newspaper_karen":{"trust":0,"reliability":0,"emotionalLoad":0}},"set_npc_memory":{"npc_newspaper_karen":{"met":true,"knows_name":true,"has_your_interest":true}},"precludes":["s5_opportunity_expired"]},{"id":"s4_fair_freeze_coalition","label":"Stop at the nuclear freeze table — the anxiety is real","time_cost":1,"energy_cost":0,"identity_tags":["risk","people"],"reaction_text":"Tom talks about the Pershing II missiles like someone who stayed up late reading about them.","outcome":{"text":"You sign the petition. The pamphlet goes in your back pocket next to your class schedule. You might go to the meeting. The anxiety feels less abstract now that someone named it.","deltas":{"stress":1,"resources":{"knowledge":1,"socialLeverage":1}}}},{"id":"s4_fair_browse_nothing","label":"Walk the whole fair without stopping — take it in first","time_cost":1,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You make a full loop. You collect three flyers you didn''t mean to take.","outcome":{"text":"You haven''t joined anything. You know what exists. By Thursday the newspaper pitch meeting will have happened without you. That was also a choice.","deltas":{"stress":-1}},"precludes":["s5_newspaper_pitch"]},{"id":"s4_fair_miguel","label":"Follow Miguel''s lead — let him introduce you to people","time_cost":1,"energy_cost":1,"identity_tags":["people","safety"],"reaction_text":"Miguel makes introductions like he''s doing both people a favor, which he usually is.","outcome":{"text":"By the end of the hour you''ve talked to seven people. You remember four. Miguel says ''we should get food'' and you realize you''ve been talking for ninety minutes.","deltas":{"energy":-1,"stress":-2,"resources":{"socialLeverage":4}}},"relational_effects":{"npc_floor_miguel":{"trust":2,"reliability":1,"emotionalLoad":0}},"set_npc_memory":{"npc_floor_miguel":{"met":true,"knows_name":true}}}]'::jsonb,
  ARRAY['arc_one_core', 'belonging', 'social', 'opportunity'],
  '{"min_day_index":1,"max_day_index":1,"max_total_runs":1}'::jsonb,
  190,
  true
)
