-- s4_floor_social: Common Room, 8pm
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's4_floor_social',
  'Common Room, 8pm',
  'Your RA Scott has organized a floor social in the common room.

It is: a bag of Doritos, two two-liters of Coke, and fourteen freshmen standing in a rectangle.

The TV in the corner is on but nobody''s watching — the news, something about Beirut.

Danny goes in ahead of you. Miguel is already there on the arm of the couch, talking to a girl with a Talking Heads shirt who is laughing at something he said.',
  '[{"id":"s4_floor_one_person","label":"Find one person who looks as uncertain as you","time_cost":1,"energy_cost":1,"identity_tags":["people","safety"],"reaction_text":"There''s a guy near the window reading the Doritos bag with more attention than it deserves.","outcome":{"text":"His name is Carl. From a small town in Indiana. He talks slowly and means what he says. You talk about whether college will be what you thought. Neither of you knows. By the time Scott wraps it up, you have one person you''d eat breakfast with tomorrow.","deltas":{"energy":-1,"stress":-1,"resources":{"socialLeverage":2}}}},{"id":"s4_floor_circulate","label":"Work the room — brief with everyone, committed to no one","time_cost":1,"energy_cost":2,"identity_tags":["people","achieve"],"skill_modifier":"networking","reaction_text":"You move. Names, hometowns, majors. You get good at the three-question loop.","outcome":{"text":"You''ve talked to eleven of fourteen people. You remember six. You''ve identified who''s interesting. You''re also exhausted in a way that''s hard to explain.","deltas":{"energy":-2,"stress":0,"resources":{"socialLeverage":3}}}},{"id":"s4_floor_leave_early","label":"Make an appearance and leave — twenty minutes, then back to the room","time_cost":0,"energy_cost":0,"identity_tags":["achieve","safety"],"reaction_text":"You show up, take a Coke, nod at Scott, and go.","outcome":{"text":"Scott notices. He doesn''t say anything. You have your evening back. The hallway sounds louder from inside the room than you expected.","deltas":{"stress":0,"energy":1}}}]'::jsonb,
  ARRAY['arc_one_core', 'belonging', 'roommate', 'social'],
  '{"min_day_index":1,"max_day_index":1,"max_total_runs":1}'::jsonb,
  160,
  true
)
