-- s5_opportunity_noticed: The Board Outside the Union
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's5_opportunity_noticed',
  'The Board Outside the Union',
  'Passing the student union on the way from the bookstore. The job board is just inside the door.

Most of it is standard — dining hall, library reshelving. But one index card near the top:

*Herald looking for freshman contributors. No experience needed — curiosity required. See Karen S., Student Union 204.*

Below it:

*Research Assistant — Prof. Heller, Sociology. Motivated freshman considered. Whitmore 318.*

Both cards have pull tabs. Two tabs remain on the Heller card. Five on the Herald card.',
  '[{"id":"s5_opp_take_both","label":"Take a tab from both — figure out which one later","time_cost":0,"energy_cost":0,"identity_tags":["risk"],"reaction_text":"Both tabs go in your pocket.","outcome":{"text":"You have two options now. Options have their own weight — the tabs make you think about what you actually want, which might be the point.","deltas":{"stress":1}},"set_npc_memory":{"npc_newspaper_karen":{"has_your_interest":true},"npc_prof_heller":{"you_noticed_posting":true}}},{"id":"s5_opp_take_heller","label":"Take the Heller tab — research sounds more useful","time_cost":0,"energy_cost":0,"identity_tags":["achieve"],"reaction_text":"One of only two tabs taken.","outcome":{"text":"If you go, you''ll be competing with maybe one other person. That''s manageable.","deltas":{"stress":0}},"set_npc_memory":{"npc_prof_heller":{"you_noticed_posting":true}},"precludes":["s5_newspaper_pitch"]},{"id":"s5_opp_walk_past","label":"Keep walking — you''re not ready to take something on yet","time_cost":0,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You glance and move on.","outcome":{"text":"By Thursday the Heller tab will be gone. By next Tuesday the Herald card will be down. You''ll pass the board again and it''ll be different cards. You won''t know what you walked past.","deltas":{"stress":-1}},"precludes":["s5_newspaper_pitch","s5_heller_ra_opportunity"]}]'::jsonb,
  ARRAY['arc_one_core', 'opportunity', 'work'],
  '{"min_day_index":1,"max_day_index":2,"max_total_runs":1}'::jsonb,
  140,
  true
)
