-- s5_newspaper_pitch: Student Union 204, Wednesday 7pm
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's5_newspaper_pitch',
  'Student Union 204, Wednesday 7pm',
  'Student Union 204 has seven people when you arrive, including Karen, already at the front with a legal pad.

She looks up. ''You''re from the fair?'' You say yes. She nods and writes something.

The room has the feel of something running longer than any individual person in it. Stacks of back issues. A layout board. A police scanner in the corner nobody''s turned on.

Karen gives everyone three minutes to pitch. You''re up.',
  '[{"id":"s5_pitch_real","label":"Pitch the Soviet studies professor — it''s the interesting story","time_cost":1,"energy_cost":2,"identity_tags":["risk","achieve"],"skill_modifier":"networking","reaction_text":"Karen looks up from her legal pad. Two others look up.","outcome":{"text":"''That story''s been pitched before. What''s your angle?'' You don''t have one. You say something about what it means to study an enemy you can''t visit. She writes on her pad. ''Come back Friday with three questions you''d ask him.'' You''re not in. But you''re not out.","deltas":{"energy":-2,"stress":1,"resources":{"socialLeverage":2}}},"relational_effects":{"npc_newspaper_karen":{"trust":1,"reliability":1,"emotionalLoad":0}}},{"id":"s5_pitch_safe","label":"Pitch something manageable — freshman orientation piece, first-person","time_cost":1,"energy_cost":1,"identity_tags":["safety","achieve"],"reaction_text":"Karen nods once.","outcome":{"text":"''Five hundred words by Sunday. We run first-person on the back page.'' You have an assignment. It''s not the front page. It''s real.","deltas":{"energy":-1,"resources":{"socialLeverage":1}}},"relational_effects":{"npc_newspaper_karen":{"trust":0,"reliability":1,"emotionalLoad":0}}},{"id":"s5_pitch_freeze","label":"Tell the truth — you don''t have a pitch yet","time_cost":1,"energy_cost":2,"identity_tags":["risk","people"],"reaction_text":"The room is quiet for a second.","outcome":{"text":"Karen: ''More honest than most pitches in this room.'' Dave needs a second reporter for the academic calendar story — student interviews. It''s not your story. You''re in.","deltas":{"energy":-2,"stress":2,"resources":{"socialLeverage":2}}},"relational_effects":{"npc_newspaper_karen":{"trust":2,"reliability":0,"emotionalLoad":1}}}]'::jsonb,
  ARRAY['arc_one_core', 'opportunity', 'work', 'belonging', 'social'],
  '{"min_day_index":3,"max_day_index":3,"max_total_runs":1,"requires_not_precluded":"s5_newspaper_pitch","requires_npc_met":["npc_newspaper_karen"]}'::jsonb,
  130,
  true
)
