-- s5_opportunity_expired: The Card Is Gone
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's5_opportunity_expired',
  'The Card Is Gone',
  'You pass the student union job board on the way to the dining hall.

The Herald card is gone. The Heller research assistant card is gone — replaced by something about a lost bicycle.

You weren''t ready. Or you were and didn''t move. Same result.',
  '[{"id":"s5_expired_note","label":"Note it — next time you''ll move faster","time_cost":0,"energy_cost":0,"identity_tags":["achieve"],"reaction_text":"You file it. There will be other boards.","outcome":{"text":"Probably true. The version of this week where you went to the pitch meeting exists somewhere. You didn''t go there. You try to remember what you chose instead.","deltas":{"stress":1}}},{"id":"s5_expired_accept","label":"Let it go — it wasn''t the right time","time_cost":0,"energy_cost":0,"identity_tags":["safety"],"reaction_text":"You move on.","outcome":{"text":"Fine. The dining hall is serving something that smells like chicken. You get a tray.","deltas":{"stress":-1}}}]'::jsonb,
  ARRAY['arc_one_core', 'opportunity'],
  '{"min_day_index":5,"max_day_index":5,"max_total_runs":1,"requires_not_precluded":"s5_opportunity_expired"}'::jsonb,
  80,
  true
)
