-- s6_first_contact_home: The Floor Phone
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's6_first_contact_home',
  'The Floor Phone',
  'Someone knocks on your door at 7:30pm.

The girl from room 209. ''Phone for you. The floor phone.'' You follow her to the hallway. The receiver is down, cord swinging.

Your mother.

She says your name the way she says it when she''s been waiting. Just checking in. Your father says hi. The dog has been looking for you. How is it?

The hallway is not private. Two doors are open. You can hear someone''s TV.',
  '[{"id":"s6_home_honest","label":"Tell her the truth — overwhelming and good and not sure yet","time_cost":1,"energy_cost":1,"identity_tags":["risk","people"],"reaction_text":"A pause on her end. ''That sounds right.'' She doesn''t try to fix it.","outcome":{"text":"You talk for twenty minutes. The long-distance meter runs and neither of you mentions it. You hang up feeling more anchored and more aware of how far you are. The hallway is quieter.","deltas":{"stress":-2,"energy":-1,"resources":{"socialLeverage":1}}}},{"id":"s6_home_cheerful","label":"Tell her it''s great — edit out the parts that would worry her","time_cost":1,"energy_cost":1,"identity_tags":["safety","people"],"reaction_text":"You perform fine. She sounds relieved.","outcome":{"text":"Twelve minutes. She''s glad. You hang up and stand in the hallway. You protected her from something. You''re not sure if that was generous or lonely.","deltas":{"stress":1,"energy":-1}}},{"id":"s6_home_brief","label":"Keep it short — you''ll call back when you have more to say","time_cost":0,"energy_cost":0,"identity_tags":["achieve","safety"],"reaction_text":"Five minutes. Fine, busy, I''ll call Sunday.","outcome":{"text":"You''re back in the room before Danny notices you left. You feel slightly like you''ve left something on the table but can''t name what.","deltas":{"stress":0,"energy":0}}}]'::jsonb,
  ARRAY['arc_one_core', 'home', 'social'],
  '{"min_day_index":2,"max_day_index":3,"max_total_runs":1}'::jsonb,
  150,
  true
)
