-- s6_home_contrast_moment: The Part That Doesn't Translate
INSERT INTO public.storylets (slug, title, body, choices, tags, requirements, weight, is_active)
VALUES (
  's6_home_contrast_moment',
  'The Part That Doesn''t Translate',
  'Dinner table in the dining hall.

Miguel is telling a story about his cousin''s quinceañera — the whole family from San Antonio and Laredo — and the table is laughing at the right parts.

The girl from Cincinnati mentions her boarding school. Carla talks about her dad''s work at the Board of Trade. Someone mentions their family''s lake house like it''s a direction.

You grew up somewhere. You came from something. The version of that story you tell is forming in real time.',
  '[{"id":"s6_contrast_share","label":"Tell your story — let it be what it is","time_cost":0,"energy_cost":1,"identity_tags":["risk","people"],"reaction_text":"You say where you''re from and something true about it. The table receives it.","outcome":{"text":"Miguel asks a follow-up. Carla says ''I''ve driven through there.'' The boarding school girl says nothing, which is also information. You''ve planted a flag. This version of yourself is available to build on.","deltas":{"stress":-1,"energy":-1,"resources":{"socialLeverage":2}}},"relational_effects":{"npc_floor_miguel":{"trust":1,"reliability":0,"emotionalLoad":0}}},{"id":"s6_contrast_deflect","label":"Redirect — ask Miguel a question instead","time_cost":0,"energy_cost":0,"identity_tags":["safety","people"],"reaction_text":"He answers happily. The moment passes.","outcome":{"text":"You know more about everyone at this table. They know nothing new about you. You''ve been asking questions as a way of disappearing.","deltas":{"stress":-1,"resources":{"socialLeverage":1}}}},{"id":"s6_contrast_honest_gap","label":"Name the gap — say something feels different about where you came from","time_cost":0,"energy_cost":2,"identity_tags":["risk","people"],"reaction_text":"''I feel like everyone here has a version of this story that''s bigger than mine.'' The table goes quiet.","outcome":{"text":"Miguel: ''Mine''s not bigger. It''s just louder.'' Carla says her boarding school story is the version her parents want her to tell. The girl from Cincinnati laughs and says she has no idea what she''s doing here either. The most honest moment this table has had all week.","deltas":{"stress":-3,"energy":-2,"resources":{"socialLeverage":4}}},"relational_effects":{"npc_floor_miguel":{"trust":3,"reliability":0,"emotionalLoad":1}}}]'::jsonb,
  ARRAY['arc_one_core', 'home', 'belonging', 'social'],
  '{"min_day_index":3,"max_day_index":5,"max_total_runs":1}'::jsonb,
  100,
  true
)
